def H(r_km):
    import math
    return 8537.0 * math.exp(-r_km / 8619.0)

def n_index(r_km):
    import math
    h = 8537.0 * math.exp(-r_km / 8619.0)
    return 1.0 + 0.20 * (8537.0 / h - 1.0)

def fsf(lat_deg):
    import math
    lat = max(0.1, abs(lat_deg))
    return 0.19550 / (math.sin(math.radians(lat)) ** 0.1640) * (32.974 ** (lat / 90.0))

from scipy.special import ellipe

def ew_arc(a_km, e, delta_lon_deg, r_avg_km):
    return 4.0 * a_km * ellipe(e ** 2) * (delta_lon_deg / 360.0) * (r_avg_km / a_km)
